#include "contour.h"
#include <gtest/gtest.h>

class ContourFixture : public ::testing::Test {
protected:
    Contour testContour;

    void SetUp() override {
        // Setup a simple square as test data
        testContour.points.push_back({0, 0});
        testContour.points.push_back({0, 1});
        testContour.points.push_back({1, 1});
        testContour.points.push_back({1, 0});
    }

    void TearDown() override {
        // Cleanup, if necessary
    }
};

TEST_F(ContourFixture, AreaOfSquare) {
    float calculatedArea = area(testContour);
    EXPECT_FLOAT_EQ(calculatedArea, 1.0f); // Expecting square area of 1.0
}

TEST_F(ContourFixture, NegativeAreaForReversedSquare) {
    // Reverse the order to simulate a contour traced in the opposite direction
    std::reverse(testContour.points.begin(), testContour.points.end());
    float calculatedArea = area(testContour);
    EXPECT_FLOAT_EQ(calculatedArea, -1.0f); // Expecting area of -1.0 due to reversed order
